import { FormEvent, useMemo, useState } from "react";
import { Helmet } from "react-helmet-async";
import { Link, useLocation } from "wouter";
import { ArrowRight, Calculator, Home, Search } from "lucide-react";
import { calculatorRoutes } from "@/data/siteRoutes";

const TITLE_OVERRIDES: Record<string, string> = {
  "/bmi-calculator": "BMI Calculator",
  "/bmr-calculator": "BMR Calculator",
  "/gpa-calculator": "GPA Calculator",
  "/gdp-calculator": "GDP Calculator",
  "/btu-calculator": "BTU Calculator",
  "/youtube-cpm-calculator": "YouTube CPM Calculator",
  "/bio-link-ctr-calculator": "Bio Link CTR Calculator",
  "/url-encode-tool": "URL Encode / Decode Tool",
  "/base64-tool": "Base64 Encode / Decode Tool",
  "/ohms-law-calculator": "Ohm's Law Calculator",
  "/resistor-calculator": "Resistor Color Code Calculator",
  "/dice-roller": "Dice Roller",
  "/love-calculator": "Love Calculator",
  "/day-counter": "Day Counter",
  "/day-of-week-calculator": "Day of the Week Calculator",
  "/time-card-calculator": "Time Card Calculator",
  "/time-duration-calculator": "Time Duration Calculator",
  "/time-zone-calculator": "Time Zone Calculator",
};

function titleFromPath(path: string) {
  if (TITLE_OVERRIDES[path]) return TITLE_OVERRIDES[path];
  const acronyms = new Set(["bmi", "bmr", "gpa", "gdp", "btu", "cpm", "ctr", "url", "hp", "mpg"]);
  return path
    .replace(/^\//, "")
    .split("-")
    .map((word) => (acronyms.has(word) ? word.toUpperCase() : word.charAt(0).toUpperCase() + word.slice(1)))
    .join(" ");
}

const calculators = calculatorRoutes.map((route) => ({
  href: route.path,
  title: titleFromPath(route.path),
  category: route.category,
}));

export default function NotFound() {
  const [, navigate] = useLocation();
  const [query, setQuery] = useState("");

  const results = useMemo(() => {
    const term = query.trim().toLowerCase();
    if (!term) return calculators.slice(0, 6);
    return calculators
      .filter((calculator) =>
        calculator.title.toLowerCase().includes(term) ||
        calculator.category.toLowerCase().includes(term),
      )
      .slice(0, 6);
  }, [query]);

  const submitSearch = (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    if (results[0]) navigate(results[0].href);
  };

  return (
    <>
      <Helmet>
        <title>Oops! Page Not Found | CalcHive</title>
        <meta name="description" content="The calculator or page you are looking for does not exist. Search all 258 free calculators on CalcHive." />
        <meta name="robots" content="noindex, nofollow" />
      </Helmet>

      <main className="min-h-[72vh] px-4 py-12 sm:py-16">
        <section className="mx-auto flex max-w-3xl flex-col items-center text-center">
          <div className="mb-5 flex h-16 w-16 items-center justify-center rounded-2xl border border-primary/15 bg-primary/10 text-primary shadow-sm">
            <Calculator className="h-8 w-8" />
          </div>

          <p className="mb-3 text-sm font-bold uppercase tracking-[0.24em] text-primary">404</p>
          <h1 className="mb-3 text-3xl font-black tracking-tight text-foreground sm:text-5xl">
            Oops! Page Not Found
          </h1>
          <p className="mb-8 max-w-xl text-base leading-relaxed text-muted-foreground sm:text-lg">
            The calculator or page you are looking for does not exist
          </p>

          <form onSubmit={submitSearch} className="relative mb-5 w-full max-w-xl">
            <Search className="pointer-events-none absolute left-4 top-1/2 h-5 w-5 -translate-y-1/2 text-muted-foreground" />
            <input
              type="search"
              value={query}
              onChange={(event) => setQuery(event.target.value)}
              placeholder="Search calculators..."
              className="h-14 w-full rounded-2xl border border-border bg-card pl-12 pr-4 text-base font-medium text-foreground shadow-sm outline-none transition-all placeholder:text-muted-foreground focus:border-primary/50 focus:ring-4 focus:ring-primary/10"
              aria-label="Search calculators"
            />
          </form>

          <div className="mb-8 grid w-full max-w-xl gap-2 text-left">
            {results.length > 0 ? (
              results.map((calculator) => (
                <Link
                  key={calculator.href}
                  href={calculator.href}
                  className="group flex items-center gap-3 rounded-2xl border border-border bg-card p-3 shadow-sm transition-all hover:border-primary/40 hover:bg-accent"
                >
                  <span className="flex h-10 w-10 flex-shrink-0 items-center justify-center rounded-xl bg-primary/10 text-primary">
                    <Calculator className="h-5 w-5" />
                  </span>
                  <span className="min-w-0 flex-1">
                    <span className="block truncate text-sm font-bold text-foreground group-hover:text-primary">{calculator.title}</span>
                    <span className="block text-xs font-semibold uppercase tracking-wide text-muted-foreground">{calculator.category}</span>
                  </span>
                  <ArrowRight className="h-4 w-4 flex-shrink-0 text-muted-foreground transition-all group-hover:translate-x-0.5 group-hover:text-primary" />
                </Link>
              ))
            ) : (
              <div className="rounded-2xl border border-dashed border-border bg-card p-5 text-center text-sm text-muted-foreground">
                No calculators found. Try a different search.
              </div>
            )}
          </div>

          <Link
            href="/"
            className="inline-flex items-center gap-2 rounded-full bg-primary px-6 py-3 text-sm font-bold text-primary-foreground shadow-sm transition-all hover:scale-[1.02] hover:bg-primary/90 focus:outline-none focus:ring-4 focus:ring-primary/20"
          >
            <Home className="h-4 w-4" />
            Browse All 258 calculators
          </Link>
        </section>
      </main>
    </>
  );
}


